questionText:
Que produit le code suivant ?
```jsx
function Card({ children }) {
  return &lt;View style={styles.card}&gt;{children}&lt;/View&gt;;
}

// Utilisation
&lt;Card&gt;
  &lt;Text&gt;Titre&lt;/Text&gt;
  &lt;Text&gt;Description&lt;/Text&gt;
&lt;/Card&gt;
```

Dans l'exemple ci-dessous, comment <strong>récupérer la valeur du champ nom</strong> dans le parent lorsque le bouton est cliqué ?
```jsx
function Formulaire({ onSoumettre }) {
  const [nom, setNom] = useState('');
  return (
    &lt;&gt;
      &lt;TextInput placeholder="Nom" value={nom} onChangeText={setNom} /&gt;
      &lt;Button title="Envoyer" onPress={() =&gt; ???} /&gt;
    &lt;/&gt;
  );
}

function Ecran() {
  const handleSubmit = (nom) =&gt; console.log(nom);
  return &lt;Formulaire onSoumettre={handleSubmit} /&gt;;
}
```
